INSERT IGNORE INTO answers (userId, questionId, stageId, answer, createdAt, updatedAt)
SELECT 21, q.id, q.stageId, '4', NOW(), NOW()
FROM questions q
WHERE q.stageId = 60007;

SELECT COUNT(*) as answerCount FROM answers WHERE userId = 21 AND stageId = 60007;

